// ── Helpers ──────────────────────────────────────────────────────────────────

export function getPostBySlug(slug) {
  return blogPosts.find(p => p.slug === slug) || null;
}

export function getRelatedPosts(slug, count = 3) {
  const post = getPostBySlug(slug);
  if (!post) return blogPosts.slice(0, count);
  const same = blogPosts.filter(p => p.slug !== slug && p.category === post.category);
  const diff = blogPosts.filter(p => p.slug !== slug && p.category !== post.category);
  return [...same, ...diff].slice(0, count);
}

export function getByCategory(category) {
  if (category === 'all') return blogPosts;
  return blogPosts.filter(p => p.category === category);
}

export const categories = [
  { id: 'all',       label: 'All Posts',  count: blogPosts.length },
  { id: 'services',  label: 'Services',   count: blogPosts.filter(p => p.category === 'services').length },
  { id: 'locations', label: 'Locations',  count: blogPosts.filter(p => p.category === 'locations').length },
  { id: 'guides',    label: 'Guides',     count: blogPosts.filter(p => p.category === 'guides').length },
];

export function formatDate(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
}
